#include <iostream>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long n;
    cin >> n;

    // Sum = 1*2 + 3*4 + 5*6 + ... + (n-1)*n
    // = sum_{k=1}^{n/2} (2k-1)*(2k)
    // = sum_{k=1}^{n/2} (4k^2 - 2k)
    // = 4 * sum(k^2) - 2 * sum(k)
    // = 4 * m(m+1)(2m+1)/6 - 2 * m(m+1)/2
    // where m = n/2
    long long m = n / 2;

    long long sum_sq = m * (m + 1) * (2 * m + 1) / 6;
    long long sum_k = m * (m + 1) / 2;

    long long result = 4 * sum_sq - 2 * sum_k;

    cout << result << "\n";
    return 0;
}
